import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

// Deterministic daily market data: a fluctuation % and the quarter it fell in.
function marketData() {
  var quarters = ['Q1', 'Q2', 'Q3', 'Q4']
  var out = []
  for (var i = 0; i < 92; i++) {
    var pct =
      3.2 * Math.sin(i / 4.0) +
      1.4 * Math.sin(i / 1.3) +
      0.5 * Math.cos(i / 2.7)
    out.push({
      day: i,
      pct: Math.round(pct * 100) / 100,
      q: quarters[Math.floor(i / 23) % 4],
    })
  }
  return out
}

// Register the shared records BEFORE the charts are constructed.
ApexCharts.crossfilter({ id: 'market', records: marketData() })

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [],
    options: {
      chart: {
        id: 'fluctuation',
        type: 'bar',
        height: 260,
        fontFamily: 'Helvetica, Arial, sans-serif',
        animations: { speed: 450 },
        zoom: { enabled: false },
        selection: { enabled: true },
        toolbar: {
          autoSelected: 'selection',
          tools: {
            selection: true,
            zoom: false,
            pan: false,
            reset: false,
            download: false,
          },
        },
        link: {
          id: 'market',
          dimension: function (r) {
            return r.pct
          },
          bins: { count: 24 },
          dimOpacity: 0.16,
        },
      },
      title: {
        text: 'Daily fluctuation % (brush a range here)',
        align: 'left',
      },
      plotOptions: { bar: { columnWidth: '92%' } },
      dataLabels: { enabled: false },
      xaxis: {
        type: 'numeric',
        tickAmount: 8,
        labels: {
          formatter: function (v) {
            return Number(v).toFixed(1) + '%'
          },
        },
      },
      colors: ['#6366f1'],
    },
    series1: [],
    options1: {
      chart: {
        id: 'byQuarter',
        type: 'bar',
        height: 240,
        fontFamily: 'Helvetica, Arial, sans-serif',
        animations: { speed: 450 },
        link: {
          id: 'market',
          dimension: function (r) {
            return r.q
          },
          reduce: 'count',
          seriesName: 'Days',
        },
      },
      title: { text: 'Days by quarter (crossfiltered)', align: 'left' },
      plotOptions: {
        bar: { columnWidth: '55%', borderRadius: 3, distributed: true },
      },
      legend: { show: false },
      dataLabels: { enabled: true },
      colors: ['#6366f1', '#0ea5e9', '#22c55e', '#f59e0b'],
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, and the crossfilter engine is
    // registered by the shared head script (ApexCharts.crossfilter). Poll until the
    // engine exists, then wire the readout + Reset button the same way the vanilla
    // build does.
    const timer = window.setInterval(() => {
      const cf = ApexCharts.getCrossfilter('market')
      if (!cf) return
      window.clearInterval(timer)

      const readout = document.getElementById('cf-readout')
      cf.on('change', (state) => {
        const r = state.filters.fluctuation
        if (r) {
          readout.textContent =
            'Fluctuation ' +
            r[0].toFixed(2) +
            '% to ' +
            r[1].toFixed(2) +
            '%   ->   ' +
            state.filteredCount +
            ' / ' +
            state.total +
            ' days'
        } else {
          readout.textContent = 'No filter (all ' + state.total + ' days)'
        }
      })

      document
        .getElementById('cf-reset')
        .addEventListener('click', () => cf.reset())
    }, 50)

    return () => window.clearInterval(timer)
  }, [])

  return (
    <div>
      <div className="cf-wrap">
        <div className="cf-bar">
          <button id="cf-reset">Reset</button>
          <span className="readout" id="cf-readout">
            Drag a range on the histogram to filter the quarter chart
          </span>
        </div>

        <div className="cf-card">
          <div id="chart">
            <ReactApexChart
              options={state.options}
              series={state.series}
              type="bar"
              height={260}
            />
          </div>
        </div>
        <div className="cf-card">
          <div id="chart2">
            <ReactApexChart
              options={state.options1}
              series={state.series1}
              type="bar"
              height={240}
            />
          </div>
        </div>

        <div className="cf-note">
          The top chart is a <b>histogram</b> of daily fluctuation %, binned by
          the
          <code>link</code> engine (<code>bins: &#123; count &#125;</code>) on a
          numeric x-axis. It has <code>chart.selection.enabled</code>, so
          brushing a range sets a<code>[min, max]</code> filter on the
          fluctuation dimension: the bottom chart
          <b>re-aggregates</b> to just the days in that range, and the histogram
          dims the bins outside it. Because a chart never filters itself, the
          histogram's own bars keep their full shape. <b>Reset</b> clears the
          brush.
        </div>
      </div>
    </div>
  )
}

export default ApexChart

